    CHECK (rider_assignment_mode IN ('auto', 'manual', 'third_party'));

-- -----------------------------------------------------------------------------
-- Source: 064-product-rich-attributes.sql
-- -----------------------------------------------------------------------------
-- ============================================================================
-- MIGRATION 064: Rich product attributes (POS + mobile PDP)
-- SKU code remains the canonical `sku` column; API exposes `sku_code` as alias.
-- ============================================================================

ALTER TABLE shop_products
    ADD COLUMN IF NOT EXISTS brand TEXT,
    ADD COLUMN IF NOT EXISTS weight NUMERIC(15, 4),
    ADD COLUMN IF NOT EXISTS weight_unit TEXT,
    ADD COLUMN IF NOT EXISTS size TEXT,
    ADD COLUMN IF NOT EXISTS color TEXT,
    ADD COLUMN IF NOT EXISTS material TEXT,
    ADD COLUMN IF NOT EXISTS origin_country TEXT,
    ADD COLUMN IF NOT EXISTS attributes JSONB DEFAULT '{}'::jsonb;

UPDATE shop_products SET attributes = '{}'::jsonb WHERE attributes IS NULL;

-- -----------------------------------------------------------------------------
-- Source: 065-mobile-order-inventory-deducted.sql
-- -----------------------------------------------------------------------------
-- Mobile orders: track whether physical stock was FEFO-deducted (legacy: on status Confirmed; current: on Delivered).
-- Prevents double-deduction when changing lifecycle after deploy; backfills rows already past confirmation.

ALTER TABLE mobile_orders
  ADD COLUMN IF NOT EXISTS inventory_deducted BOOLEAN NOT NULL DEFAULT FALSE;

COMMENT ON COLUMN mobile_orders.inventory_deducted IS
  'When true, shop_inventory was reduced for this order (old flow at Confirmed, new flow at Delivered).';

UPDATE mobile_orders
SET inventory_deducted = TRUE
WHERE status IN ('Confirmed', 'Packed', 'OutForDelivery', 'Delivered')
  AND COALESCE(inventory_deducted, FALSE) = FALSE;

-- -----------------------------------------------------------------------------
-- Source: 066-pos-archive-history-days.sql
-- -----------------------------------------------------------------------------
-- How many days of sales to load in the POS Sales Archive (default 30)
ALTER TABLE pos_settings ADD COLUMN IF NOT EXISTS archive_history_days INTEGER NOT NULL DEFAULT 30;

-- -----------------------------------------------------------------------------
-- Source: 067-backfill-product-brand-id-from-text.sql
-- -----------------------------------------------------------------------------
-- Link shop_products.brand (SKU text) to shop_brands and set brand_id where missing.

UPDATE shop_products p
SET brand_id = b.id
FROM shop_brands b
WHERE p.tenant_id = b.tenant_id
  AND p.brand_id IS NULL
  AND p.brand IS NOT NULL
  AND TRIM(p.brand) <> ''
  AND LOWER(TRIM(p.brand)) = LOWER(TRIM(b.name));

-- -----------------------------------------------------------------------------
-- Source: 068-recipes.sql
-- -----------------------------------------------------------------------------
-- ============================================================================
-- MIGRATION 068: Recipe catalog (POS config + mobile discovery & cart bridge)
-- ============================================================================

CREATE TABLE IF NOT EXISTS recipe_categories (
    id TEXT PRIMARY KEY DEFAULT uuid_generate_v4()::text,
    tenant_id TEXT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    name TEXT NOT NULL,
    image_url TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
    UNIQUE(tenant_id, name)
);

CREATE TABLE IF NOT EXISTS recipes (
    id TEXT PRIMARY KEY DEFAULT uuid_generate_v4()::text,
    tenant_id TEXT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    title TEXT NOT NULL,
    slug TEXT NOT NULL,
    description TEXT,
    image_url TEXT,
    video_url TEXT,
    prep_time_minutes INTEGER NOT NULL DEFAULT 0,
    cook_time_minutes INTEGER NOT NULL DEFAULT 0,
    servings INTEGER NOT NULL DEFAULT 1,
    difficulty TEXT,
    cuisine TEXT,
    calories INTEGER,
    category_id TEXT REFERENCES recipe_categories(id) ON DELETE SET NULL,
    is_active BOOLEAN NOT NULL DEFAULT TRUE,
    is_featured BOOLEAN NOT NULL DEFAULT FALSE,
    is_quick_meal BOOLEAN NOT NULL DEFAULT FALSE,
    is_budget_meal BOOLEAN NOT NULL DEFAULT FALSE,
    is_trending BOOLEAN NOT NULL DEFAULT FALSE,
    created_by TEXT REFERENCES users(id) ON DELETE SET NULL,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
    UNIQUE(tenant_id, slug)
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_recipes_tenant_title_lower
    ON recipes (tenant_id, LOWER(TRIM(title)));

CREATE INDEX IF NOT EXISTS idx_recipes_title ON recipes (tenant_id, title);
CREATE INDEX IF NOT EXISTS idx_recipes_category ON recipes (tenant_id, category_id);
CREATE INDEX IF NOT EXISTS idx_recipes_active ON recipes (tenant_id, is_active);
CREATE INDEX IF NOT EXISTS idx_recipes_featured ON recipes (tenant_id, is_featured) WHERE is_featured = TRUE;
CREATE INDEX IF NOT EXISTS idx_recipes_trending ON recipes (tenant_id, is_trending) WHERE is_trending = TRUE;

CREATE TABLE IF NOT EXISTS recipe_ingredients (
    id TEXT PRIMARY KEY DEFAULT uuid_generate_v4()::text,
    tenant_id TEXT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    recipe_id TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,
    ingredient_name TEXT NOT NULL,
    normalized_name TEXT NOT NULL DEFAULT '',
    quantity NUMERIC(15, 4) NOT NULL DEFAULT 1,
    unit TEXT NOT NULL DEFAULT '',
    optional BOOLEAN NOT NULL DEFAULT FALSE,
    product_id TEXT NOT NULL REFERENCES shop_products(id) ON DELETE CASCADE,
    sort_order INTEGER NOT NULL DEFAULT 0
);

CREATE INDEX IF NOT EXISTS idx_recipe_ingredients_recipe ON recipe_ingredients (recipe_id);
CREATE INDEX IF NOT EXISTS idx_recipe_ingredients_product ON recipe_ingredients (product_id);
CREATE INDEX IF NOT EXISTS idx_recipe_ingredients_norm ON recipe_ingredients (tenant_id, normalized_name);

CREATE TABLE IF NOT EXISTS recipe_steps (
    id TEXT PRIMARY KEY DEFAULT uuid_generate_v4()::text,
    tenant_id TEXT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    recipe_id TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,
    step_number INTEGER NOT NULL,
    instruction TEXT NOT NULL,
    image_url TEXT
);

CREATE INDEX IF NOT EXISTS idx_recipe_steps_recipe ON recipe_steps (recipe_id);

CREATE TABLE IF NOT EXISTS user_saved_recipes (
    id TEXT PRIMARY KEY DEFAULT uuid_generate_v4()::text,
    tenant_id TEXT NOT NULL REFERENCES tenants(id) ON DELETE CASCADE,
    user_id TEXT NOT NULL REFERENCES mobile_customers(id) ON DELETE CASCADE,
    recipe_id TEXT NOT NULL REFERENCES recipes(id) ON DELETE CASCADE,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    UNIQUE(user_id, recipe_id)
);

CREATE INDEX IF NOT EXISTS idx_user_saved_recipes_user ON user_saved_recipes (tenant_id, user_id);
CREATE INDEX IF NOT EXISTS idx_user_saved_recipes_recipe ON user_saved_recipes (recipe_id);

-- Row level security
ALTER TABLE recipe_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE recipes ENABLE ROW LEVEL SECURITY;
ALTER TABLE recipe_ingredients ENABLE ROW LEVEL SECURITY;
ALTER TABLE recipe_steps ENABLE ROW LEVEL SECURITY;
ALTER TABLE user_saved_recipes ENABLE ROW LEVEL SECURITY;

DO $$
DECLARE
    tbl TEXT;
BEGIN
    FOR tbl IN SELECT unnest(ARRAY['recipe_categories', 'recipes', 'recipe_ingredients', 'recipe_steps', 'user_saved_recipes'])
    LOOP
        EXECUTE format('DROP POLICY IF EXISTS tenant_isolation ON %I', tbl);
        EXECUTE format(
            'CREATE POLICY tenant_isolation ON %I FOR ALL USING (tenant_id = get_current_tenant_id()) WITH CHECK (tenant_id = get_current_tenant_id())',
            tbl
        );
    END LOOP;
END $$;

-- -----------------------------------------------------------------------------
-- Source: 069-weekly-menu-planner.sql
-- -----------------------------------------------------------------------------
-- ============================================================================
-- MIGRATION 069: Weekly menu planner, shopping lists, menu templates
